+        if (model.input_dim <= 0 || model.hidden_dim <= 0 || model.num_classes <= 0) {
+            throw std::runtime_error("model dimensions must be positive");
+        }
+
+        model.input_weight = json_vector(
+            root, "input_weight",
+            static_cast<std::size_t>(model.hidden_dim) * model.input_dim);
+        model.input_bias = json_vector(root, "input_bias", model.hidden_dim);
+        model.hidden_weight = json_vector(
+            root, "hidden_weight",
+            static_cast<std::size_t>(model.hidden_dim) * model.hidden_dim);
+        model.hidden_bias = json_vector(root, "hidden_bias", model.hidden_dim);
+        model.output_weight = json_vector(
+            root, "output_weight",
+            static_cast<std::size_t>(model.num_classes) * model.hidden_dim);
+        model.output_bias = json_vector(root, "output_bias", model.num_classes);
