+        cJSON_Delete(root);
+        return model;
+    } catch (...) {
+        cJSON_Delete(root);
+        throw;
+    }
+}
+
+std::vector<double> linear(const std::vector<double>& input,
+                           const std::vector<double>& weight,
+                           const std::vector<double>& bias,
+                           int out_dim,
+                           int in_dim) {
+    std::vector<double> output(out_dim);
+    for (int out = 0; out < out_dim; ++out) {
+        double sum = bias[out];
+        const std::size_t row = static_cast<std::size_t>(out) * in_dim;
+        for (int in = 0; in < in_dim; ++in) {
+            sum += weight[row + in] * input[in];
+        }
+        output[out] = sum;
+    }
+    return output;
+}
+
+void relu_in_place(std::vector<double>& values) {
+    for (double& value : values) {
+        if (value < 0.0) {
+            value = 0.0;
+        }
+    }
+}
+
+std::vector<double> image_to_input(const std::string& path, int input_dim) {
+    const double side = std::sqrt(static_cast<double>(input_dim));
+    const int target = static_cast<int>(side + 0.5);
+    if (target <= 0 || target * target != input_dim) {
+        throw std::runtime_error("input dimension must be a square image");
+    }
+
+    std::vector<unsigned char> rgba;
+    unsigned width = 0;
+    unsigned height = 0;
+    const unsigned error = lodepng::decode(rgba, width, height, path);
+    if (error != 0) {
+        throw std::runtime_error(std::string("failed to decode PNG: ") +
+                                 lodepng_error_text(error));
+    }
+    if (width == 0 || height == 0) {
+        throw std::runtime_error("image has invalid dimensions");
+    }
+
+    std::vector<double> gray(static_cast<std::size_t>(width) * height);
+    for (std::size_t i = 0; i < gray.size(); ++i) {
+        const std::size_t px = i * 4;
+        const double r = rgba[px + 0];
+        const double g = rgba[px + 1];
+        const double b = rgba[px + 2];
+        const double a = rgba[px + 3] / 255.0;
+        gray[i] = ((0.299 * r + 0.587 * g + 0.114 * b) / 255.0) * a;
+    }
+
+    if (static_cast<int>(width) == target && static_cast<int>(height) == target) {
+        return gray;
+    }
+
+    std::vector<double> resized(static_cast<std::size_t>(target) * target);
+    for (int y = 0; y < target; ++y) {
+        const double src_y = (y + 0.5) * height / target - 0.5;
+        const int y0 = std::max(0, static_cast<int>(std::floor(src_y)));
+        const int y1 = std::min(static_cast<int>(height) - 1, y0 + 1);
+        const double fy = src_y - y0;
+
+        for (int x = 0; x < target; ++x) {
+            const double src_x = (x + 0.5) * width / target - 0.5;
+            const int x0 = std::max(0, static_cast<int>(std::floor(src_x)));
+            const int x1 = std::min(static_cast<int>(width) - 1, x0 + 1);
+            const double fx = src_x - x0;
+
+            const double v00 = gray[static_cast<std::size_t>(y0) * width + x0];
+            const double v01 = gray[static_cast<std::size_t>(y0) * width + x1];
+            const double v10 = gray[static_cast<std::size_t>(y1) * width + x0];
+            const double v11 = gray[static_cast<std::size_t>(y1) * width + x1];
+            const double top = v00 * (1.0 - fx) + v01 * fx;
+            const double bottom = v10 * (1.0 - fx) + v11 * fx;
+            resized[static_cast<std::size_t>(y) * target + x] =
+                top * (1.0 - fy) + bottom * fy;
+        }
+    }
+    return resized;
+}
+
+int predict(const Model& model, const std::vector<double>& input) {
+    if (input.size() != static_cast<std::size_t>(model.input_dim)) {
+        throw std::runtime_error("image input size does not match model");
+    }
+
+    std::vector<double> hidden = linear(input, model.input_weight, model.input_bias,
+                                        model.hidden_dim, model.input_dim);
+    relu_in_place(hidden);
+
+    std::vector<double> hidden2 = linear(hidden, model.hidden_weight, model.hidden_bias,
+                                         model.hidden_dim, model.hidden_dim);
+    relu_in_place(hidden2);
+
+    std::vector<double> logits = linear(hidden2, model.output_weight, model.output_bias,
+                                        model.num_classes, model.hidden_dim);
+    return static_cast<int>(std::max_element(logits.begin(), logits.end()) - logits.begin());
+}
+
+}  // namespace
+
+int main(int argc, char** argv) {
+    if (argc != 3) {
+        std::cerr << "usage: " << argv[0] << " weights.json image.png\n";
+        return 1;
+    }
+
+    try {
+        const Model model = load_model(argv[1]);
+        const std::vector<double> input = image_to_input(argv[2], model.input_dim);
